         const monitorIndex = metaWindow.get_monitor();
         const grid = this._grids.get(monitorIndex);

-        // Remove from grid
+        // Destroy any existing clone
+        this._inputRouter.hidePreview();
+        this._scaleManager.destroyClone(metaWindow);
+
         if (grid)
             grid.removeWindow(windowId);

-        // Destroy old clone (also removes container from parent)
-        this._scaleManager.destroyClone(metaWindow);
+        if (!grid)
+            return;

-        if (isFullSize(newScale)) {
-            // Restore to full size — no clone needed
-            if (grid) {
-                const frameRect = metaWindow.get_frame_rect();
-                const span = cellsForWindow(
-                    frameRect.width, frameRect.height,
-                    grid.cellWidth, grid.cellHeight, 1.0);
-                grid.placeWindow(windowId, span.cols, span.rows);
-            }
-        } else {
-            // Scale down — create new clone
-            this._createAndPlaceClone(metaWindow, newScale);
+        // For manual zoom, resize the real window to occupy fewer grid
+        // cells. The window stays interactive — content reflows but clicks,
+        // typing, and dragging all work normally. No clone needed.
+        // Calculate how many cells the window should occupy at this scale
+        // by scaling the full-grid-width equivalent.
+        const wa = global.workspace_manager.get_active_workspace().get_work_area_for_monitor(monitorIndex);
+        const frameRect = metaWindow.get_frame_rect();
+        const fullSpan = cellsForWindow(
+            frameRect.width, frameRect.height,
+            grid.cellWidth, grid.cellHeight, 1.0);
+        const scaledCols = Math.max(1, Math.round(fullSpan.cols * newScale));
+        const scaledRows = Math.max(1, Math.round(fullSpan.rows * newScale));
+        const span = {cols: scaledCols, rows: scaledRows};
+
+        const pos = grid.placeWindow(windowId, span.cols, span.rows);
+        if (pos) {
+            const rect = grid.cellToPixels(pos.col, pos.row, span.cols, span.rows);
+            metaWindow.move_resize_frame(true,
+                wa.x + rect.x, wa.y + rect.y, rect.width, rect.height);
         }
     }
